	server := httptest.NewServer(mux)
	defer server.Close()

	reqBody := map[string]interface{}{
		"requests": []map[string]interface{}{
			{
				"requestId":    "1",
				"namespaceKey": "default",
				"flagKey":      "boolean-flag",
				"entityId":     "user123",
			},
			{
				"requestId":    "2",
				"namespaceKey": "default",
				"flagKey":      "variant-flag",
				"entityId":     "user123",
			},
